const msg = $input.first().json.message;
const text = (msg?.text || '').trim();
const chatId = String(msg.chat.id);
const base = 'http://host.docker.internal:8080/api';

const spaceIdx = text.indexOf(' ');
const cmd = (spaceIdx === -1 ? text : text.slice(0, spaceIdx)).toLowerCase();
const args = spaceIdx === -1 ? '' : text.slice(spaceIdx + 1).trim();

const direct = (reply) => [{ json: { chatId, direct: true, reply } }];
const http = (method, url, body = null) => [{ json: { chatId, direct: false, method, url, body, cmd } }];

switch (cmd) {
  case '/start': case '/ayuda': case '/help':
    return direct('📋 *Comandos:*\n\n`/note <título>` — nueva nota\n`/note <título> | <contenido>` — con contenido\n`/notas` — activas\n`/archivadas` — archivadas\n`/archivar <id>` — archivar\n`/desarchivar <id>` — desarchivar\n`/borrar <id>` — eliminar\n`/titulo <id> <título>` — editar título\n`/contenido <id> <texto>` — editar contenido\n`/categorias` — listar categorías\n`/categoria <nombre>` — crear categoría\n`/renombrar <id> <nombre>` — renombrar\n`/borrarcategoria <id>` — eliminar categoría\n`/asignar <id_nota> <id_cat>` — asignar categoría');
  case '/note': case '/nota': {
    if (!args) return direct('Uso: `/note <título>`');
    const [title, ...rest] = args.split('|').map(s => s.trim());
    return http('POST', `${base}/notes`, { title, content: rest.join('|').trim() || null });
  }
  case '/notas': return http('GET', `${base}/notes/active`);
  case '/archivadas': return http('GET', `${base}/notes/archived`);
  case '/archivar': { const id = parseInt(args); if (!id) return direct('Uso: `/archivar <id>`'); return http('POST', `${base}/notes/${id}/archive`); }
  case '/desarchivar': { const id = parseInt(args); if (!id) return direct('Uso: `/desarchivar <id>`'); return http('POST', `${base}/notes/${id}/unarchive`); }
  case '/borrar': { const id = parseInt(args); if (!id) return direct('Uso: `/borrar <id>`'); return http('DELETE', `${base}/notes/${id}`); }
  case '/titulo': { const m = args.match(/^(\d+)\s+(.+)$/); if (!m) return direct('Uso: `/titulo <id> <título>`'); return http('PUT', `${base}/notes/${m[1]}/title`, { title: m[2].trim() }); }
  case '/contenido': { const m = args.match(/^(\d+)\s+(.+)$/); if (!m) return direct('Uso: `/contenido <id> <texto>`'); return http('PUT', `${base}/notes/${m[1]}/content`, { content: m[2].trim() }); }
  case '/categorias': return http('GET', `${base}/categories`);
  case '/categoria': { if (!args) return direct('Uso: `/categoria <nombre>`'); return http('POST', `${base}/categories`, { name: args }); }
  case '/renombrar': { const m = args.match(/^(\d+)\s+(.+)$/); if (!m) return direct('Uso: `/renombrar <id> <nombre>`'); return http('PUT', `${base}/categories/${m[1]}`, { name: m[2].trim() }); }
  case '/borrarcategoria': { const id = parseInt(args); if (!id) return direct('Uso: `/borrarcategoria <id>`'); return http('DELETE', `${base}/categories/${id}`); }
  case '/asignar': { const m = args.match(/^(\d+)\s+(\d+)$/); if (!m) return direct('Uso: `/asignar <id_nota> <id_cat>`'); return http('PUT', `${base}/notes/${m[1]}/category`, { categoryId: parseInt(m[2]) }); }
  default: return [];
}

const parsed = $('Parse Command').item.json;
const { chatId, method, url, cmd } = parsed;

if (method === 'GET' && url.includes('/notes')) {
  const notes = $input.all().map(i => i.json);
  if (!notes.length) return [{ json: { chatId, text: url.includes('archived') ? 'No tenés notas archivadas.' : 'No tenés notas activas.' } }];
  const header = url.includes('archived') ? '📦 *Archivadas:*' : '📋 *Notas activas:*';
  const lines = notes.map(n => {
    const cat = n.category ? ' ['+n.category.name+']' : '';
    const content = n.content ? '\n   _'+n.content+'_' : '';
    return '*#'+n.id+'*'+cat+' — '+n.title+content;
  });
  return [{ json: { chatId, text: header + '\n\n' + lines.join('\n') } }];
}

if (method === 'GET' && url.includes('/categories')) {
  const cats = $input.all().map(i => i.json);
  if (!cats.length) return [{ json: { chatId, text: 'No tenés categorías.' } }];
  return [{ json: { chatId, text: '🏷️ *Categorías:*\n\n' + cats.map(c => '*#'+c.id+'* — '+c.name).join('\n') } }];
}

const replies = {'/note':'Nota guardada ✅','/nota':'Nota guardada ✅','/archivar':'Nota archivada 📦','/desarchivar':'Nota desarchivada ✅','/borrar':'Nota eliminada 🗑️','/titulo':'Título actualizado ✅','/contenido':'Contenido actualizado ✅','/categoria':'Categoría creada ✅','/renombrar':'Categoría renombrada ✅','/borrarcategoria':'Categoría eliminada 🗑️','/asignar':'Categoría asignada ✅'};
return [{ json: { chatId, text: replies[cmd] || '✅' } }];
